parameters.prompt:
=You are a job search assistant. Search and compile a list of software engineering jobs that match the following criteria:

**Role:** {{ $('Set Job Criteria').item.json.role }}
**Experience Level:** {{ $('Set Job Criteria').item.json.experienceLevel }}
**Location:** {{ $('Set Job Criteria').item.json.location }}
**Salary Range:** {{ $('Set Job Criteria').item.json.salaryRange }}
**Remote/Hybrid/Onsite:** {{ $('Set Job Criteria').item.json.workType }}
**Keywords:** {{ $('Set Job Criteria').item.json.keywords }}

For each job, provide the following information in JSON format:
- jobTitle: string
- company: string
- location: string
- salaryRange: string (if available)
- jobType: string (Full-time, Part-time, Contract, etc.)
- workMode: string (Remote, Hybrid, Onsite)
- experience: string
- applyUrl: string
- description: string (brief summary)
- postedDate: string
- tags: array of strings (relevant skills/technologies)

Return the results as a valid JSON array of job objects. Search across LinkedIn, Indeed, Glassdoor, and other major job boards.

parameters.jsCode:
// Set your job search criteria here
return [
  {
    json: {
      role: 'Software Engineer',
      experienceLevel: 'Mid-level (3-5 years)',
      location: 'United States, Remote',
      salaryRange: '$80,000 - $150,000',
      workType: 'Remote or Hybrid',
      keywords: 'JavaScript, Node.js, React, Python, AWS'
    }
  }
];

// Parse the AI response and extract job listings
const response = items[0].json.response || items[0].json.text || '';

let jobs = [];

try {
  // Try to extract JSON from the response
  const jsonMatch = response.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    jobs = JSON.parse(jsonMatch[0]);
  } else {
    // If no JSON found, return empty array
    console.log('No valid JSON found in response');
    return [];
  }
} catch (error) {
  console.error('Error parsing JSON:', error);
  return [];
}

// Format and return jobs
return jobs.map(job => ({
  json: {
    jobTitle: job.jobTitle || 'Unknown',
    company: job.company || 'Unknown',
    location: job.location || 'Not specified',
    salaryRange: job.salaryRange || 'Not disclosed',
    jobType: job.jobType || 'Full-time',
    workMode: job.workMode || 'Not specified',
    experience: job.experience || 'Not specified',
    applyUrl: job.applyUrl || '',
    description: job.description || '',
    postedDate: job.postedDate || new Date().toISOString().split('T')[0],
    tags: job.tags || [],
    status: 'New',
    priority: 'Medium',
    addedDate: new Date().toISOString().split('T')[0]
  }
}));

// Rank jobs based on criteria
const jobData = items[0].json;

// Calculate priority score
let score = 0;
const tagsStr = (jobData.tags || []).join(' ').toLowerCase();

// Preferred technologies (adjust based on your preferences)
const preferredTech = ['react', 'node.js', 'python', 'aws', 'typescript', 'kubernetes'];
preferredTech.forEach(tech => {
  if (tagsStr.includes(tech.toLowerCase())) {
    score += 10;
  }
});

// Remote/Hybrid preference
if (jobData.workMode && (jobData.workMode.toLowerCase().includes('remote') || jobData.workMode.toLowerCase().includes('hybrid'))) {
  score += 15;
}

// Salary consideration (if disclosed)
if (jobData.salaryRange && !jobData.salaryRange.toLowerCase().includes('not disclosed')) {
  score += 10;
}

// Recent posting
if (jobData.postedDate) {
  const daysAgo = Math.floor((new Date() - new Date(jobData.postedDate)) / (1000 * 60 * 60 * 24));
  if (daysAgo <= 7) score += 20;
  else if (daysAgo <= 14) score += 10;
}

// Assign priority
let priority = 'Low';
if (score >= 40) priority = 'High';
else if (score >= 20) priority = 'Medium';

return [{
  json: {
    ...jobData,
    priority,
    score
  }
}];

// Aggregate results for summary email
const totalJobs = items.length;
const highPriority = items.filter(item => item.json.priority === 'High').length;
const mediumPriority = items.filter(item => item.json.priority === 'Medium').length;
const lowPriority = items.filter(item => item.json.priority === 'Low').length;

const topJobs = items
  .sort((a, b) => (b.json.score || 0) - (a.json.score || 0))
  .slice(0, 5)
  .map(item => `• **${item.json.jobTitle}** at **${item.json.company}** (${item.json.location}) - Priority: ${item.json.priority}`);

return [{
  json: {
    totalJobs,
    highPriority,
    mediumPriority,
    lowPriority,
    topJobsList: topJobs.join('\n'),
    searchDate: new Date().toISOString().split('T')[0]
  }
}];

